diff --git a/src/parse-transport-mode.ts b/src/parse-transport-mode.ts
index cbbcd5f16b20e4460b8f942594fa1c0f12a68b3d..e36a569e92bba6f45d7b7b9358f8ec723ac6c116 100644
--- a/src/parse-transport-mode.ts
+++ b/src/parse-transport-mode.ts
@@ -1,8 +1,37 @@
 export type TransportMode = "direct" | "relay";

 export function parseTransportMode(value: string): TransportMode | null {
-  if (value === "direct" || value === "relay") {
-    return value;
+  const trimmed = value.trim();
+  const quote = trimmed[0];
+  let candidate: string;
+
+  if (quote === '"' || quote === "'") {
+    const closingQuote = trimmed.indexOf(quote, 1);
+    if (closingQuote === -1) {
+      return null;
+    }
+
+    candidate = trimmed.slice(1, closingQuote);
+    if (!isEmptyOrComment(trimmed.slice(closingQuote + 1))) {
+      return null;
+    }
+  } else {
+    const commentStart = trimmed.search(/[ \t][#;]/);
+    if (
+      commentStart !== -1 &&
+      !isEmptyOrComment(trimmed.slice(commentStart))
+    ) {
+      return null;
+    }
+    candidate = commentStart === -1 ? trimmed : trimmed.slice(0, commentStart);
+  }
+
+  if (candidate === "direct" || candidate === "relay") {
+    return candidate;
   }
   return null;
 }
+
+function isEmptyOrComment(value: string): boolean {
+  return value === "" || /^[ \t]+[#;][^\r\n]*$/.test(value);
+}
diff --git a/tests/parse-transport-mode.test.ts b/tests/parse-transport-mode.test.ts
index 4acb9e544456420f68b09dc2dd268c0131e1bb18..31d496f81f8ec4ed09d516f523d705f78e5ac8d0 100644
--- a/tests/parse-transport-mode.test.ts
+++ b/tests/parse-transport-mode.test.ts
@@ -7,8 +7,36 @@ describe("parseTransportMode", () => {
     expect(parseTransportMode("relay")).toBe("relay");
   });

+  it("accepts surrounding configuration whitespace", () => {
+    expect(parseTransportMode("  direct\n")).toBe("direct");
+    expect(parseTransportMode("\trelay  ")).toBe("relay");
+  });
+
+  it("accepts quoted configuration values", () => {
+    expect(parseTransportMode("'direct'")).toBe("direct");
+    expect(parseTransportMode('"relay"')).toBe("relay");
+  });
+
+  it("accepts trailing configuration comments", () => {
+    expect(parseTransportMode("direct # connect without a relay")).toBe(
+      "direct",
+    );
+    expect(parseTransportMode('"relay" ; use the configured relay')).toBe(
+      "relay",
+    );
+  });
+
   it("rejects unsupported values", () => {
     expect(parseTransportMode("proxy")).toBeNull();
     expect(parseTransportMode("DIRECT")).toBeNull();
   });
+
+  it("rejects malformed configuration values", () => {
+    expect(parseTransportMode('"direct')).toBeNull();
+    expect(parseTransportMode("'relay\"")).toBeNull();
+    expect(parseTransportMode('"direct" extra')).toBeNull();
+    expect(parseTransportMode("direct#not-a-comment")).toBeNull();
+    expect(parseTransportMode("' direct '")).toBeNull();
+    expect(parseTransportMode("direct # comment\nrelay")).toBeNull();
+  });
 });
